import{_ as e,c as a,o as i,a1 as o}from"./chunks/framework.DILC4Csi.js";const f=JSON.parse(`{"title":"Platform and Integration: macOS, Windows, Linux Terminal Features","description":"Learn opencode-notify's feature differences across macOS, Windows, and Linux. Master terminal support (37+ emulators), focus detection, click-to-focus, and custom sounds. Includes platform feature comparison, terminal detection mechanisms, and configuration guides.","frontmatter":{"title":"Platform and Integration: macOS, Windows, Linux Terminal Features","sidebarTitle":"Platform and Integration","subtitle":"Platform and Integration","description":"Learn opencode-notify's feature differences across macOS, Windows, and Linux. Master terminal support (37+ emulators), focus detection, click-to-focus, and custom sounds. Includes platform feature comparison, terminal detection mechanisms, and configuration guides.","tags":["Platform Features","Terminal Support","System Compatibility"],"prerequisite":["start-quick-start","start-how-it-works"]},"headers":[],"relativePath":"kdcokenny/opencode-notify/platforms/index.md","filePath":"kdcokenny/opencode-notify/platforms/index.md"}`),n={name:"kdcokenny/opencode-notify/platforms/index.md"};function r(s,t,d,l,c,u){return i(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="platform-and-integration" tabindex="-1">Platform and Integration <a class="header-anchor" href="#platform-and-integration" aria-label="Permalink to &quot;Platform and Integration&quot;">​</a></h1><p>This chapter helps you understand opencode-notify&#39;s feature differences across operating systems, master platform-specific configurations, and optimize your terminal for best performance.</p><h2 id="learning-path" tabindex="-1">Learning Path <a class="header-anchor" href="#learning-path" aria-label="Permalink to &quot;Learning Path&quot;">​</a></h2><h3 id="_1-macos-platform-features" tabindex="-1">1. <a href="./../macos/">macOS Platform Features</a> <a class="header-anchor" href="#_1-macos-platform-features" aria-label="Permalink to &quot;1. [macOS Platform Features](../macos/)&quot;">​</a></h3><p>Learn about advanced features on macOS, including smart focus detection, click-to-focus notifications, and custom sounds.</p><ul><li>Focus Detection: Automatically determine if the terminal is the active window</li><li>Click-to-Focus: Automatically switch to terminal when clicking notification</li><li>Custom Sounds: Configure exclusive sounds for different events</li><li>37+ Terminal Support: Including Ghostty, iTerm2, VS Code integrated terminal, etc.</li></ul><h3 id="_2-windows-platform-features" tabindex="-1">2. <a href="./../windows/">Windows Platform Features</a> <a class="header-anchor" href="#_2-windows-platform-features" aria-label="Permalink to &quot;2. [Windows Platform Features](../windows/)&quot;">​</a></h3><p>Master notification basics and configuration methods on Windows platform.</p><ul><li>Native Notifications: Use Windows 10/11 notification center</li><li>Notification Permissions: Ensure OpenCode has permission to send notifications</li><li>Basic Configuration: Configuration file locations on Windows</li><li>Limitations: Focus detection not currently supported on Windows</li></ul><h3 id="_3-linux-platform-features" tabindex="-1">3. <a href="./../linux/">Linux Platform Features</a> <a class="header-anchor" href="#_3-linux-platform-features" aria-label="Permalink to &quot;3. [Linux Platform Features](../linux/)&quot;">​</a></h3><p>Understand notification mechanisms and dependency installation on Linux platform.</p><ul><li>libnotify Integration: Send notifications via notify-send</li><li>Desktop Environment Support: GNOME, KDE Plasma, XFCE, and other mainstream environments</li><li>Dependency Installation: Installation commands for different distributions</li><li>Limitations: Focus detection not currently supported on Linux</li></ul><h3 id="_4-supported-terminals" tabindex="-1">4. <a href="./../terminals/">Supported Terminals</a> <a class="header-anchor" href="#_4-supported-terminals" aria-label="Permalink to &quot;4. [Supported Terminals](../terminals/)&quot;">​</a></h3><p>View all 37+ supported terminal emulators and learn about automatic detection mechanisms.</p><ul><li>Terminal Detection: How to automatically identify your terminal type</li><li>Terminal List: Complete list of supported terminals</li><li>Manual Configuration: How to manually specify terminal when auto-detection fails</li><li>Special Terminals: Handling VS Code integrated terminal, remote SSH sessions, etc.</li></ul><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Before studying this chapter, ensure you have completed</p><ul><li>✅ <strong><a href="./../../start/quick-start/">Quick Start</a></strong>: Completed opencode-notify installation</li><li>✅ <strong><a href="./../../start/how-it-works/">How It Works</a></strong>: Understood the four notification types and intelligent filtering mechanism</li></ul></div><h2 id="platform-selection-guide" tabindex="-1">Platform Selection Guide <a class="header-anchor" href="#platform-selection-guide" aria-label="Permalink to &quot;Platform Selection Guide&quot;">​</a></h2><p>Choose the corresponding chapter based on your operating system:</p><table tabindex="0"><thead><tr><th>Operating System</th><th>Recommended Learning Order</th><th>Core Features</th></tr></thead><tbody><tr><td><strong>macOS</strong></td><td>1. macOS Platform Features → 4. Supported Terminals</td><td>Focus detection, click-to-focus, custom sounds</td></tr><tr><td><strong>Windows</strong></td><td>2. Windows Platform Features → 4. Supported Terminals</td><td>Native notifications, basic configuration</td></tr><tr><td><strong>Linux</strong></td><td>3. Linux Platform Features → 4. Supported Terminals</td><td>libnotify integration, dependency installation</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">General Recommendation</p><p>Regardless of your platform, Lesson 4 &quot;Supported Terminals&quot; is worth studying. It helps you understand terminal detection mechanisms and solve configuration issues.</p></div><h2 id="feature-comparison-table" tabindex="-1">Feature Comparison Table <a class="header-anchor" href="#feature-comparison-table" aria-label="Permalink to &quot;Feature Comparison Table&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>macOS</th><th>Windows</th><th>Linux</th></tr></thead><tbody><tr><td>Native Notifications</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Terminal Focus Detection</td><td>✅</td><td>❌</td><td>❌</td></tr><tr><td>Click-to-Focus Notifications</td><td>✅</td><td>❌</td><td>❌</td></tr><tr><td>Custom Sounds</td><td>✅</td><td>✅</td><td>✅ (partial)</td></tr><tr><td>Quiet Hours</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Parent Session Check</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>37+ Terminal Support</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Automatic Terminal Detection</td><td>✅</td><td>✅</td><td>✅</td></tr></tbody></table><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>After completing this chapter, you will understand feature differences and configuration methods across platforms.</p><p>Recommended to continue learning:</p><h3 id="advanced-configuration" tabindex="-1"><a href="./../../advanced/config-reference/">Advanced Configuration</a> <a class="header-anchor" href="#advanced-configuration" aria-label="Permalink to &quot;[Advanced Configuration](../../advanced/config-reference/)&quot;">​</a></h3><p>Deep dive into all configuration file options and master advanced configuration techniques.</p><ul><li>Complete Configuration Reference: Detailed explanation of all configuration items</li><li>Quiet Hours Deep Dive: How to set up and how it works</li><li>Terminal Detection Principles: Internal mechanisms of automatic detection</li><li>Advanced Usage: Configuration tips and best practices</li></ul><h3 id="troubleshooting" tabindex="-1"><a href="./../../faq/troubleshooting/">Troubleshooting</a> <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;[Troubleshooting](../../faq/troubleshooting/)&quot;">​</a></h3><p>When you encounter issues, check solutions to common problems.</p><ul><li>Notifications Not Showing: Permissions and system settings issues</li><li>Focus Detection Failure: Terminal configuration and detection mechanisms</li><li>Configuration Errors: Configuration file format and field descriptions</li><li>Sound Issues: Sound configuration and system compatibility</li></ul><div class="info custom-block"><p class="custom-block-title">Learning Path Recommendation</p><p>If you&#39;re just getting started, it&#39;s recommended to learn in the order: <strong>Platform Chapters → Advanced Configuration → Troubleshooting</strong>. If you encounter a specific issue, you can jump directly to the troubleshooting chapter.</p></div>',33)])])}const p=e(n,[["render",r]]);export{f as __pageData,p as default};
